# break və continue nümunəsi
count = 0
while count < 10:
    count += 1
    if count == 5:
        break
    if count % 2 == 0:
        continue
    print(count)

// JavaScript kodu
let count = 1;
while (count <= 5) {
    console.log(count);
    count++;
}

# Səhv idarəetməsi
value = '10'
try:
    value = int(value)
    while value > 0:
        print(value)
        value -= 1
except ValueError:
    print('Xəta: Dəyər rəqəm olmalıdır!')

